// Supabase helpers
async function fetchTx(){const{data,error}=await supabase.from("transactions").select("*").order("created_at",{ascending:false});if(error)return[];return data.map(r=>({id:r.id,userId:r.user_id,type:r.type,category:r.category,emoji:r.emoji,amount:parseFloat(r.amount),note:r.note||"",date:r.date,recurring:r.recurring,sg:r.split_group_id,stotal:r.split_total?parseFloat(r.split_total):null,paidBy:r.paid_by||null,receiptUrl:r.receipt_url||null}))}
async function insertTx(tx){await supabase.from("transactions").insert({user_id:tx.userId,type:tx.type,category:tx.category,emoji:tx.emoji,amount:tx.amount,note:tx.note,date:tx.date,recurring:tx.recurring,split_group_id:tx.sg||null,split_total:tx.stotal||null,paid_by:tx.paidBy||null,receipt_url:tx.receiptUrl||null})}
async function updateTx(id,f){const m={};if(f.amount!==undefined)m.amount=f.amount;if(f.note!==undefined)m.note=f.note;if(f.date!==undefined)m.date=f.date;await supabase.from("transactions").update(m).eq("id",id)}
async function uploadReceipt(file){const p=`receipts/${Date.now()}_${Math.random().toString(36).slice(2)}.${file.name.split('.').pop()}`;const{error}=await supabase.storage.from("receipts").upload(p,file);if(error)return null;return supabase.storage.from("receipts").getPublicUrl(p).data?.publicUrl||null}
async function deleteTxById(id){await supabase.from("transactions").delete().eq("id",id)}
async function deleteTxByGroup(gid){await supabase.from("transactions").delete().eq("split_group_id",gid)}
async function getS(key,fb){try{const{data,error}=await supabase.from("settings").select("value").eq("key",key).single();if(error||!data)return fb;let v=data.value;if(typeof v==='string')try{v=JSON.parse(v)}catch{};if(typeof v==='string')try{v=JSON.parse(v)}catch{};return v}catch{return fb}}
async function setS(key,val){await supabase.from("settings").upsert({key,value:val,updated_at:new Date().toISOString()})}

function AnimNum({value}){const[d,setD]=useState(value);const r=useRef();useEffect(()=>{let s=d,e=value,st=null;const go=ts=>{if(!st)st=ts;let p=Math.min((ts-st)/450,1);p=1-Math.pow(1-p,3);setD(s+(e-s)*p);if(p<1)r.current=requestAnimationFrame(go)};r.current=requestAnimationFrame(go);return()=>cancelAnimationFrame(r.current)},[value]);return<>£{Math.abs(d).toFixed(2)}</>}
function Donut({data,size=115}){if(!data.length)return null;const total=data.reduce((s,d)=>s+d.value,0);const pal=["#FF6B35","#E040FB","#00BFA5","#FFB300","#42A5F5","#EF5350","#AB47BC","#66BB6A"];let acc=0;const cx=size/2,cy=size/2,rad=size*0.37,sw=size*0.15;return<div style={{position:"relative",width:size,height:size,flexShrink:0}}><svg width={size} height={size}>{data.map((d,i)=>{const pct=d.value/total,start=acc;acc+=pct;const a1=start*2*Math.PI-Math.PI/2,a2=(start+pct)*2*Math.PI-Math.PI/2;return<path key={i} d={`M ${cx+rad*Math.cos(a1)} ${cy+rad*Math.sin(a1)} A ${rad} ${rad} 0 ${pct>0.5?1:0} 1 ${cx+rad*Math.cos(a2)} ${cy+rad*Math.sin(a2)}`} fill="none" stroke={pal[i%pal.length]} strokeWidth={sw} strokeLinecap="round" style={{animation:`dd 0.8s ease ${i*0.08}s both`}}/>})}</svg><div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}><span style={{fontSize:size*0.12,fontWeight:700,fontFamily:"'Fraunces',serif"}}>{fmt(total)}</span></div></div>}
function BarChart({data,color,maxVal}){const mx=maxVal||Math.max(...data.map(d=>d.value),1);return<div style={{display:"flex",alignItems:"flex-end",gap:3,height:100,padding:"0 4px"}}>{data.map((d,i)=><div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:2}}><span style={{fontSize:8,fontWeight:600,opacity:0.7}}>{d.value>0?fmt(d.value):""}</span><div style={{width:"100%",maxWidth:28,borderRadius:4,background:color,opacity:d.value>0?0.8:0.15,height:`${Math.max((d.value/mx)*70,2)}px`,animation:`bg 0.6s ease ${i*0.05}s both`}}/><span style={{fontSize:8,opacity:0.5}}>{d.label}</span></div>)}</div>}

