  const[convFrom,setConvFrom]=useState("GBP");const[convTo,setConvTo]=useState("EUR");const[convAmt,setConvAmt]=useState("");const[convResult,setConvResult]=useState(null);const[convLoading,setConvLoading]=useState(false);
