  useEffect(()=>{(async()=>{const[t,b,d,th,cc,sh,pin,gl,wl]=await Promise.all([fetchTx(),getS("monthly_budget",1500),getS("dark_mode",false),getS("theme","sunset"),getS("custom_categories",{income:[],expense:[]}),getS("settle_history",[]),getS("app_pin",null),getS("savings_goals",[]),getS("wishlist",[])]);setTxs(t);setBudget(parseFloat(b)||1500);setBgtIn(String(parseFloat(b)||1500));setDark(d===true||d==="true");setTheme((typeof th==='string'&&THEMES[th])?th:"sunset");setCustomCats(cc&&typeof cc==='object'?cc:{income:[],expense:[]});setSettleHistory(Array.isArray(sh)?sh:[]);setStoredPin(pin?String(pin):null);setGoals(Array.isArray(gl)?gl:[]);setWishlist(Array.isArray(wl)?wl:[]);if(!pin){setLocked(false);setSettingPin(true)};setReady(true)})()},[]);
  useEffect(()=>{const ch=supabase.channel("bb-rt").on("postgres_changes",{event:"*",schema:"public",table:"transactions"},async()=>setTxs(await fetchTx())).on("postgres_changes",{event:"*",schema:"public",table:"settings"},async()=>{setBudget(parseFloat(await getS("monthly_budget",1500))||1500);setDark((await getS("dark_mode",false))===true)}).subscribe();return()=>supabase.removeChannel(ch)},[]);

  const flash=(msg,type="success")=>{setToast({msg,type});setTimeout(()=>setToast(null),2400)};
  const allCats={income:[...DEFAULT_CATEGORIES.income,...(customCats.income||[])],expense:[...DEFAULT_CATEGORIES.expense,...(customCats.expense||[])]};
  const th=THEMES[theme]||THEMES.sunset;
  const c=dark?{bg:"#0D0D14",card:"#161622",ca:"#1C1C2A",p:th.g1,pg:`${th.g1}18`,inc:"#34D399",ig:"rgba(52,211,153,0.09)",exp:"#F87171",eg:"rgba(248,113,113,0.09)",tx:"#EEEEF2",sf:"#8585A0",mu:"#50506A",bd:"#252535",ac:th.accent,ag:`${th.accent}18`,sh:"0 3px 14px rgba(0,0,0,0.3)",g1:th.g1,g2:th.g2}:{bg:"#F4F1EA",card:"#FFFFFF",ca:"#FFF8F0",p:th.g1,pg:`${th.g1}0F`,inc:"#16A34A",ig:"rgba(22,163,74,0.06)",exp:"#DC2626",eg:"rgba(220,38,38,0.06)",tx:"#1A1A2E",sf:"#6B6B80",mu:"#A0A0B4",bd:"#E5E1D9",ac:th.accent,ag:`${th.accent}0F`,sh:"0 2px 8px rgba(0,0,0,0.035)",g1:th.g1,g2:th.g2};

  const mTx=txs.filter(x=>x.date.startsWith(month)&&(filter==="all"||x.userId===filter));
  const totI=mTx.filter(x=>x.type==="income").reduce((s,x)=>s+x.amount,0);const totE=mTx.filter(x=>x.type==="expense").reduce((s,x)=>s+x.amount,0);const bal=totI-totE;const bPct=budget>0?Math.min((totE/budget)*100,100):0;
  const ebc={};mTx.filter(x=>x.type==="expense").forEach(x=>{ebc[x.category]=(ebc[x.category]||0)+x.amount});const sExp=Object.entries(ebc).sort((a,b)=>b[1]-a[1]);
  const uStats=USERS.map(u=>{const ut=txs.filter(x=>x.date.startsWith(month)&&x.userId===u.id);return{...u,exp:ut.filter(x=>x.type==="expense").reduce((s,x)=>s+x.amount,0)}});
  const splitGrps={};mTx.filter(x=>x.sg).forEach(x=>{if(!splitGrps[x.sg])splitGrps[x.sg]=[];splitGrps[x.sg].push(x)});const splitKeys=Object.keys(splitGrps);
  const splitDebts={};txs.filter(x=>x.date.startsWith(month)&&x.sg&&x.paidBy).forEach(tx=>{if(!splitDebts[tx.sg])splitDebts[tx.sg]={paidBy:tx.paidBy,total:tx.stotal||tx.amount*2,half:tx.amount,emoji:tx.emoji,category:tx.category,note:tx.note,date:tx.date}});
  let runBal=0;const debtItems=[];Object.entries(splitDebts).forEach(([gid,d])=>{if(d.paidBy==="pranav")runBal+=d.half;else runBal-=d.half;debtItems.push({...d,gid,owes:d.paidBy==="pranav"?"kesha":"pranav",amount:d.half})});
  settleHistory.filter(s=>s.month===month).forEach(s=>{if(s.from==="kesha")runBal-=s.amount;else runBal+=s.amount});
  const settleAmt=Math.abs(runBal);const whoOwes=runBal>0?"kesha":"pranav";const whoIsOwed=runBal>0?"pranav":"kesha";
  const filteredTx=mTx.filter(tx=>{if(searchCat!=="all"&&tx.category!==searchCat)return false;if(searchQuery){const q=searchQuery.toLowerCase();return tx.category.toLowerCase().includes(q)||tx.note.toLowerCase().includes(q)||String(tx.amount).includes(q)}return true});
  const calcStreak=()=>{const today=new Date();let s=0;for(let i=0;i<365;i++){const d=new Date(today);d.setDate(d.getDate()-i);if(txs.some(x=>x.date===d.toISOString().split("T")[0]))s++;else break}return s};
  const streak=calcStreak();const todayTip=TIPS[new Date().getDate()%TIPS.length];
  const reportData=()=>{const ms=[];for(let i=5;i>=0;i--){const d=new Date();d.setMonth(d.getMonth()-i);const key=mk(d);const mt=txs.filter(x=>x.date.startsWith(key));ms.push({label:MO[d.getMonth()],income:mt.filter(x=>x.type==="income").reduce((s,x)=>s+x.amount,0),expense:mt.filter(x=>x.type==="expense").reduce((s,x)=>s+x.amount,0)})}return ms};

  const navM=d=>{const[y,m]=month.split("-").map(Number);setMonth(mk(new Date(y,m-1+d)))};const[cy,cm]=month.split("-").map(Number);const mLabel=`${MO[cm-1]} ${cy}`;const isNow=month===mk(new Date());
  const reset=()=>{setCat(null);setAmt("");setNote("");setDate(td());setRecurring(false);setSplit("solo");setReceiptFile(null);setReceiptPreview(null)};
